('Turmeric Powder','spice-powders',array['125g','250g','500g']),('Dhaniya Powder','spice-powders',array['125g','250g','500g']),('Red Chilli Powder','spice-powders',array['150g','250g','500g']),('Kashmiri Chilli Powder','spice-powders',array['100g','250g','500g']),('Soup Powder','masalas',array['125g','250g','500g']),('Chettinad Chicken Masala','masalas',array['125g','250g','500g']),('Chettinad Paneer Masala','masalas',array['125g','250g','500g']),('Chettinad Mushroom Masala','masalas',array['125g','250g','500g']),('Kurma Powder','masalas',array['100g','250g','500g']),('Spice Powder','masalas',array['125g','250g','500g']),('Mutton Powder','masalas',array['125g','250g','500g']),('Sambar Powder','masalas',array['125g','250g','500g']),('Rasam Powder','masalas',array['125g','250g','500g']),('Idli Podi','traditional-podi',array['150g']),('Chutney Podi','traditional-podi',array['150g']),('Paruppu Podi','traditional-podi',array['150g']),('Curry Leaves Podi','traditional-podi',array['150g']),('Moringa Leaves Podi','traditional-podi',array['150g']),('Chettinad Chukka Powder','masalas',array['150g']))
insert into public.products(category_id,name,slug,description,ingredients) select c.id,s.name,lower(regexp_replace(s.name,'[^a-z0-9]+','-','g')),'Freshly ground in small batches.','Whole spices and herbs. No artificial colours or preservatives.' from seed s join public.categories c on c.slug=s.category on conflict(slug) do nothing;
insert into public.product_variants(product_id,weight,price,stock,sku) select p.id,w,case when w='500g' then 230 when w='250g' then 150 else 90 end,30,upper(replace(p.slug,'-',''))||'-'||upper(w) from public.products p cross join unnest(case when p.name in ('Idli Podi','Chutney Podi','Paruppu Podi','Curry Leaves Podi','Moringa Leaves Podi','Chettinad Chukka Powder') then array['150g'] else array['125g','250g','500g'] end) w on conflict(sku) do nothing;
